import json, sys
# Look for recent messages with user 6687d4d2d1f8eda5231c6809b1a26204
for line in sys.stdin:
    try:
        data = json.loads(line.strip()) if line.strip().startswith('{') else None
    except:
        pass
" 2>/dev/null || echo "Could not parse"

